#include <stdio.h>
#include <stdlib.h>

// Structure to represent a student
typedef struct {
    int height;
    int weight;
} Student;

// Comparison function for sorting students
int compareStudents(const void *a, const void *b) {
    Student *s1 = (Student *)a;
    Student *s2 = (Student *)b;
    if (s1->height != s2->height) return s1->height - s2->height;
    return s1->weight - s2->weight;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Student students[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &students[i].height, &students[i].weight);
        }
        qsort(students, N, sizeof(Student), compareStudents);
        int teams = 0;
        int teamSizes[N];
        int teamIndex = 0;
        while (teamIndex < N) {
            int teamSize = 0;
            int maxWeight = 0;
            int maxHeight = 0;
            for (int i = teamIndex; i < N; i++) {
                if (students[i].weight > maxWeight || students[i].height > maxHeight) {
                    teamSize++;
                    maxWeight = students[i].weight;
                    maxHeight = students[i].height;
                }
            }
            teamSizes[teams] = teamSize;
            teams++;
            teamIndex += teamSize;
        }
        printf("%d\n", teams);
        for (int i = 0; i < teams; i++) {
            printf("%d ", teamSizes[i]);
        }
        printf("\n");
    }
    return 0;
}

