import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Student implements Comparable<Student> {
        int height;
        int weight;
        Student(int height, int weight) {
            this.height = height;
            this.weight = weight;
        }
        @Override
        public int compareTo(Student other) {
            if (this.height != other.height) return this.height - other.height;
            return this.weight - other.weight;
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Student[] students = new Student[N];
            for (int i = 0; i < N; i++) {
                students[i] = new Student(scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(students);
            int teams = 0;
            int[] teamSizes = new int[N];
            int teamIndex = 0;
            while (teamIndex < N) {
                int teamSize = 0;
                int maxWeight = 0;
                int maxHeight = 0;
                for (int i = teamIndex; i < N; i++) {
                    if (students[i].weight > maxWeight || students[i].height > maxHeight) {
                        teamSize++;
                        maxWeight = students[i].weight;
                        maxHeight = students[i].height;
                    }
                }
                teamSizes[teams] = teamSize;
                teams++;
                teamIndex += teamSize;
            }
            System.out.println(teams);
            for (int i = 0; i < teams; i++) {
                System.out.print(teamSizes[i] + " ");
            }
            System.out.println();
        }
    }
}

